import slugify from 'slugify'

const ROOT_FONT_SIZE = 16
const GENERATOR_NAME = 'scripts/build-tailwind-theme.mjs'

const GENERATED_FILE_HEADER = [
  '/*',
  ` * This file is generated by ${GENERATOR_NAME}.`,
  ' * Do not edit directly.',
  ' */',
  '',
].join('\n')

const ROOT_ALIAS_COMMENT = '/* Compatibility aliases for authored CSS */'
const UTILITY_COMMENT =
  '/* Generated custom utilities backed by theme tokens */'

export const slugTokenName = (name) => slugify(name, { lower: true })

export const normalizeTokenValue = (value) =>
  Array.isArray(value) ? value.join(', ') : `${value}`

export const createClampValue = ({ min, max }, viewports) => {
  if (min === max) {
    return `${min / ROOT_FONT_SIZE}rem`
  }

  const minSize = min / ROOT_FONT_SIZE
  const maxSize = max / ROOT_FONT_SIZE
  const minViewport = viewports.min / ROOT_FONT_SIZE
  const maxViewport = viewports.max / ROOT_FONT_SIZE
  const slope = (maxSize - minSize) / (maxViewport - minViewport)
  const intersection = -1 * minViewport * slope + minSize

  return `clamp(${minSize}rem, ${intersection.toFixed(2)}rem + ${(
    slope * 100
  ).toFixed(2)}vw, ${maxSize}rem)`
}

const createEntries = (items, valueBuilder) =>
  items.map((item) => ({
    name: slugTokenName(item.name),
    value: valueBuilder(item),
  }))

const formatThemeSection = (title, prefix, entries) => {
  const lines = entries.map(
    ({ name, value }) =>
      `  --${prefix}-${name}: ${normalizeTokenValue(value)};`,
  )

  return [`  /* ${title} */`, ...lines].join('\n')
}

const formatRootAliasSection = (title, entries) => {
  const lines = entries.map(
    ({ name, value }) => `  --${name}: ${normalizeTokenValue(value)};`,
  )

  return [`  /* ${title} */`, ...lines].join('\n')
}

const createSpacingUtilityBlocks = (spacingEntries) =>
  spacingEntries.flatMap(({ name }) => [
    `@utility flow-space-${name} {`,
    `  --flow-space: var(--spacing-${name});`,
    `}`,
    '',
    `@utility region-space-${name} {`,
    `  --region-space: var(--spacing-${name});`,
    `}`,
    '',
    `@utility gutter-${name} {`,
    `  --gutter: var(--spacing-${name});`,
    `}`,
    '',
  ])

export const buildTailwindCssArtifacts = ({
  colorTokens,
  fontTokens,
  spacingTokens,
  textSizeTokens,
  textLeadingTokens,
  textWeightTokens,
  viewportTokens,
}) => {
  const colors = createEntries(colorTokens, ({ value }) => value)
  const fonts = createEntries(fontTokens, ({ value }) => value)
  const spacing = createEntries(spacingTokens, (token) =>
    createClampValue(token, viewportTokens),
  )
  const textSizes = createEntries(textSizeTokens, (token) =>
    createClampValue(token, viewportTokens),
  )
  const lineHeights = createEntries(textLeadingTokens, ({ value }) => value)
  const fontWeights = createEntries(textWeightTokens, ({ value }) => value)
  const breakpoints = [
    { name: 'sm', value: `${viewportTokens.min}px` },
    { name: 'md', value: `${viewportTokens.mid}px` },
    { name: 'lg', value: `${viewportTokens.max}px` },
  ]

  const themeSections = [
    formatThemeSection('Colors', 'color', colors),
    formatThemeSection('Spacing', 'spacing', spacing),
    formatThemeSection('Typography', 'text', textSizes),
    formatThemeSection('Line Heights', 'leading', lineHeights),
    formatThemeSection('Font Families', 'font', fonts),
    formatThemeSection('Font Weights', 'font-weight', fontWeights),
    formatThemeSection('Breakpoints', 'breakpoint', breakpoints),
  ]

  const spacingAliases = spacing.map(({ name }) => ({
    name: `space-${name}`,
    value: `var(--spacing-${name})`,
  }))
  const sizeAliases = textSizes.map(({ name }) => ({
    name: `size-${name}`,
    value: `var(--text-${name})`,
  }))
  const fontWeightAliases = fontWeights.map(({ name }) => ({
    name: `font-${name}`,
    value: `var(--font-weight-${name})`,
  }))
  const legacyGrayAliases = [
    { name: 'gray-2', value: 'var(--color-gray-200)' },
    { name: 'gray-8', value: 'var(--color-gray-800)' },
    { name: 'gray-11', value: 'var(--color-gray-1100)' },
  ]

  const compatSections = [
    formatRootAliasSection('Spacing Aliases', spacingAliases),
    formatRootAliasSection('Text Size Aliases', sizeAliases),
    formatRootAliasSection('Font Weight Aliases', fontWeightAliases),
    formatRootAliasSection('Legacy Gray Aliases', legacyGrayAliases),
  ]

  const utilityBlocks = createSpacingUtilityBlocks(spacing)

  return {
    themeCss: [
      GENERATED_FILE_HEADER.trimEnd(),
      '@theme static {',
      themeSections.join('\n\n'),
      '}',
      '',
    ].join('\n'),
    compatCss: [
      GENERATED_FILE_HEADER.trimEnd(),
      ROOT_ALIAS_COMMENT,
      ':root {',
      compatSections.join('\n\n'),
      '}',
      '',
    ].join('\n'),
    utilitiesCss: [
      GENERATED_FILE_HEADER.trimEnd(),
      UTILITY_COMMENT,
      utilityBlocks.join('\n').trimEnd(),
      '',
    ].join('\n'),
  }
}
